#include <bits/stdc++.h>
using namespace std;

const int N=255;

struct Node{
    int t,x,y;
}f[N];

int n,m,t,k,c[N];
long long a[N][N][30],v[N],p[N];
bool b[N][N];

void add(int x,int y,int z){
    b[x][y+n*(z-1)]=1;
}

bool cmp(Node u,Node v){
    return u.t<v.t;
}

int main(){
    scanf("%d%d%d%d",&n,&m,&t,&k);
    for(int i=1;i<=n;i++){
        scanf("%d",&c[i]);
        for(int j=1;j<5;j++)
            b[i+j*n][i+(j-1)*n]=1;
    }
    for(int i=1;i<=m;i++){
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        add(u,v,w);
    }
    for(int i=1;i<=k;i++)
        scanf("%d%d%d",&f[i].t,&f[i].x,&f[i].y);
    sort(f+1,f+k+1,cmp);
    memset(a,0xcf,sizeof(a));
    for(int i=1;i<=5*n;i++)
        for(int j=1;j<=5*n;j++)
            if(b[i][j])
                a[i][j][0]=c[j];
    for(int x=1;x<30;x++)
        for(int i=1;i<=5*n;i++)
            for(int j=1;j<=5*n;j++)
                for(int k=1;k<=5*n;k++)
                    a[i][j][x]=max(a[i][j][x],a[i][k][x-1]+a[k][j][x-1]);
    memset(v,0xcf,sizeof(v));
    v[1]=c[1];
    f[k+1].t=t;
    for(int i=1;i<=k+1;i++){
        for(int j=0;j<30;j++)
            if((f[i].t-f[i-1].t)&(1<<j)){
                memset(p,0xcf,sizeof(p));
                for(int x=1;x<=5*n;x++)
                    for(int y=1;y<=5*n;y++)
                        p[x]=max(p[x],v[y]+a[y][x][j]);
                for(int x=1;x<=5*n;x++)
                    v[x]=p[x];
            }
        if(i<=k)
            v[f[i].x]+=f[i].y;
    }
    printf("%lld",max(-1ll,v[1]));
    return 0;
}
